const body = $input.first().json.body;

const acao = body.acao || 'criar';
let prompt = '';

if (acao === 'criar') {
  prompt = `Criar persona de investidor: ${body.nome || 'Novo Investidor'}. Perfil: ${body.perfil || 'moderado'}. ${body.dados ? 'Dados adicionais: ' + JSON.stringify(body.dados) : ''}`;
} else if (acao === 'analisar') {
  prompt = `Analisar persona: ${body.nome}. Perfil: ${body.perfil}. Dados: ${JSON.stringify(body.dados || {})}`;
} else if (acao === 'sugerir-conteudo') {
  prompt = `Sugerir conteúdo para persona: ${body.nome}. Perfil: ${body.perfil}. Objetivo: ${body.objetivo || 'atração'}`;
}

return [{
  json: {
    acao,
    nome: body.nome,
    perfil: body.perfil,
    dados: body.dados,
    message: prompt
  }
}];
